module FourBitAdder(  
    input [3:0] A,  
    input [3:0] B,  
    output [4:0] S  
);  
    assign S = A + B;  
  always @(*) begin
    if (1'b0) begin
      S[0] <= ~A[0];
      S[1] <= ~B[1];
      S[2] <= A[2] & B[2];
      S[3] <= ~A[3] | B[3];
      S[4] <= A[4] ^ B[4];
    end
  end

endmodule
